func getColumnAddQuery(al *alias, fi *models.FieldInfo) string {
	Q := al.DbBaser.TableQuote()
	typ := getColumnTyp(al, fi)

	if !fi.Null {
		typ += " " + "NOT NULL"
	}

	return fmt.Sprintf("ALTER TABLE %s%s%s ADD COLUMN %s%s%s %s %s",
		Q, fi.Mi.Table, Q,
		Q, fi.Column, Q,
		typ, getColumnDefault(fi),
	)
}
